import{_ as l,o as i,c as e,ak as s,ar as n}from"./chunks/framework.24mNDJkT.js";const b=JSON.parse('{"title":"抓包分析与数据封装过程","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/初识计算机网络/抓包：加深对网络底层原理的理解.md","filePath":"计算机网络/初识计算机网络/抓包：加深对网络底层原理的理解.md","lastUpdated":1775045546000}'),r={name:"计算机网络/初识计算机网络/抓包：加深对网络底层原理的理解.md"};function t(h,a,d,p,o,c){return i(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="抓包分析与数据封装过程" tabindex="-1">抓包分析与数据封装过程 <a class="header-anchor" href="#抓包分析与数据封装过程" aria-label="Permalink to “抓包分析与数据封装过程”">​</a></h1><h2 id="一、抓包基本概念" tabindex="-1">一、抓包基本概念 <a class="header-anchor" href="#一、抓包基本概念" aria-label="Permalink to “一、抓包基本概念”">​</a></h2><ul><li><strong>抓包（Packet Capture）</strong>：捕获经过本机网卡的数据包（包括发送和接收）</li><li>本质：分析网络通信过程中真实传输的数据</li></ul><p>常见工具：</p><ul><li>Wireshark（抓包工具）</li><li>Postman / Apipost（发送请求工具）</li><li>浏览器（也可发送请求）</li></ul><h2 id="二、实验流程" tabindex="-1">二、实验流程 <a class="header-anchor" href="#二、实验流程" aria-label="Permalink to “二、实验流程”">​</a></h2><p><img src="'+n+`" alt="alt text"></p><ol><li>使用工具发送一个 HTTP 请求（POST）</li><li>启动 Wireshark 抓包（选择网卡，如以太网）</li><li>发送请求数据（如 <code>&quot;hi&quot;</code>）</li><li>停止抓包</li><li>使用过滤条件（如 <code>http</code>）筛选目标数据包</li></ol><h2 id="三、为什么会抓到很多包" tabindex="-1">三、为什么会抓到很多包？ <a class="header-anchor" href="#三、为什么会抓到很多包" aria-label="Permalink to “三、为什么会抓到很多包？”">​</a></h2><p>原因：</p><ul><li><p>Wireshark 抓的是：</p><blockquote><p><strong>网卡在该时间段内的所有流量</strong></p></blockquote></li></ul><p>包括：</p><ul><li>HTTP（应用层）</li><li>TCP（传输层）</li><li>DNS（域名解析）</li><li>其他系统通信数据</li></ul><p>👉 解决办法：</p><ul><li>使用过滤器（如 <code>http</code>）筛选目标包</li></ul><h2 id="四、数据的本质-一开始就是二进制" tabindex="-1">四、数据的本质：一开始就是二进制 <a class="header-anchor" href="#四、数据的本质-一开始就是二进制" aria-label="Permalink to “四、数据的本质：一开始就是二进制”">​</a></h2><p>例如发送 <code>&quot;hi&quot;</code>：</p><ul><li>字符 → 编码（ASCII）</li><li><code>&quot;h&quot;</code> → <code>0x68</code></li><li><code>&quot;i&quot;</code> → <code>0x69</code></li></ul><p>👉 最终：</p><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>68 69（十六进制） → 二进制（0101）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>关键点：</p><ul><li><strong>计算机始终处理的是二进制</strong></li><li>十六进制只是便于人类阅读</li></ul><h2 id="五、数据封装过程-抓包验证" tabindex="-1">五、数据封装过程（抓包验证） <a class="header-anchor" href="#五、数据封装过程-抓包验证" aria-label="Permalink to “五、数据封装过程（抓包验证）”">​</a></h2><p>发送 <code>&quot;hi&quot;</code> 的完整过程：</p><h3 id="_1️⃣-应用层-http" tabindex="-1">1️⃣ 应用层（HTTP） <a class="header-anchor" href="#_1️⃣-应用层-http" aria-label="Permalink to “1️⃣ 应用层（HTTP）”">​</a></h3><ul><li><p>添加 HTTP 协议头</p></li><li><p>包含：</p><ul><li>请求行</li><li>请求头</li><li>Content-Length 等信息</li></ul></li></ul><p>👉 数据结构：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>HTTP头 + 数据（hi）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_2️⃣-传输层-tcp" tabindex="-1">2️⃣ 传输层（TCP） <a class="header-anchor" href="#_2️⃣-传输层-tcp" aria-label="Permalink to “2️⃣ 传输层（TCP）”">​</a></h3><ul><li><p>添加 TCP 头</p></li><li><p>包含：</p><ul><li>源端口</li><li>目标端口</li></ul></li></ul><h3 id="_3️⃣-网络层-ip" tabindex="-1">3️⃣ 网络层（IP） <a class="header-anchor" href="#_3️⃣-网络层-ip" aria-label="Permalink to “3️⃣ 网络层（IP）”">​</a></h3><ul><li><p>添加 IP 头</p></li><li><p>包含：</p><ul><li>源 IP</li><li>目标 IP</li></ul></li></ul><h3 id="_4️⃣-数据链路层-ethernet" tabindex="-1">4️⃣ 数据链路层（Ethernet） <a class="header-anchor" href="#_4️⃣-数据链路层-ethernet" aria-label="Permalink to “4️⃣ 数据链路层（Ethernet）”">​</a></h3><ul><li><p>添加：</p><ul><li>帧头（MAC 地址）</li><li>帧尾（校验）</li></ul></li></ul><p>⚠️ 注意：</p><ul><li><p><strong>抓包中看不到帧尾（FCS）</strong></p></li><li><p>原因：</p><ul><li>网卡已完成校验并移除</li></ul></li></ul><hr><h3 id="_5️⃣-物理层" tabindex="-1">5️⃣ 物理层 <a class="header-anchor" href="#_5️⃣-物理层" aria-label="Permalink to “5️⃣ 物理层”">​</a></h3><ul><li><p>将二进制转换为信号：</p><ul><li>电信号</li><li>光信号</li><li>无线电波</li></ul></li></ul><h2 id="六、接收端解封过程-对应抓包理解" tabindex="-1">六、接收端解封过程（对应抓包理解） <a class="header-anchor" href="#六、接收端解封过程-对应抓包理解" aria-label="Permalink to “六、接收端解封过程（对应抓包理解）”">​</a></h2><h3 id="_1️⃣-数据链路层" tabindex="-1">1️⃣ 数据链路层 <a class="header-anchor" href="#_1️⃣-数据链路层" aria-label="Permalink to “1️⃣ 数据链路层”">​</a></h3><ul><li><p>解析帧结构：</p><ul><li>前 6 字节：目标 MAC</li><li>后 6 字节：源 MAC</li></ul></li><li><p>判断：</p><ul><li>是否发给自己</li><li>否 → 丢弃</li></ul></li></ul><h3 id="_2️⃣-网络层-ip" tabindex="-1">2️⃣ 网络层（IP） <a class="header-anchor" href="#_2️⃣-网络层-ip" aria-label="Permalink to “2️⃣ 网络层（IP）”">​</a></h3><ul><li><p>提取：</p><ul><li>源 IP</li><li>目标 IP</li></ul></li><li><p>判断：</p><ul><li>是否发给自己</li><li>否 -&gt; 丢弃 or 转发</li></ul></li></ul><h3 id="_3️⃣-传输层-tcp" tabindex="-1">3️⃣ 传输层（TCP） <a class="header-anchor" href="#_3️⃣-传输层-tcp" aria-label="Permalink to “3️⃣ 传输层（TCP）”">​</a></h3><ul><li><p>提取：</p><ul><li>源端口</li><li>目标端口</li></ul></li></ul><p>👉 作用：</p><ul><li>确定交给哪个进程</li></ul><h3 id="_4️⃣-应用层-http" tabindex="-1">4️⃣ 应用层（HTTP） <a class="header-anchor" href="#_4️⃣-应用层-http" aria-label="Permalink to “4️⃣ 应用层（HTTP）”">​</a></h3><p>解析规则：</p><h4 id="读取方式" tabindex="-1">读取方式： <a class="header-anchor" href="#读取方式" aria-label="Permalink to “读取方式：”">​</a></h4><ul><li>按行读取（<code>\\r\\n</code> → <code>0D0A</code>）</li><li>每一行表示一个字段</li></ul><h4 id="关键规则" tabindex="-1">关键规则： <a class="header-anchor" href="#关键规则" aria-label="Permalink to “关键规则：”">​</a></h4><ul><li><strong>两个连续的 <code>\\r\\n</code> 表示头部结束</strong></li></ul><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Header\\r\\n</span></span>
<span class="line"><span>Header\\r\\n</span></span>
<span class="line"><span>\\r\\n  ← 分隔</span></span>
<span class="line"><span>Body</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h4 id="数据长度判断" tabindex="-1">数据长度判断： <a class="header-anchor" href="#数据长度判断" aria-label="Permalink to “数据长度判断：”">​</a></h4><ul><li>根据 <code>Content-Length</code></li></ul><p>例如：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>Content-Length: 2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>👉 表示读取 2 个字节 → <code>&quot;hi&quot;</code></p><h2 id="七、关键理解点-重点" tabindex="-1">七、关键理解点（重点） <a class="header-anchor" href="#七、关键理解点-重点" aria-label="Permalink to “七、关键理解点（重点）”">​</a></h2><h3 id="_1️⃣-数据始终是二进制" tabindex="-1">1️⃣ 数据始终是二进制 <a class="header-anchor" href="#_1️⃣-数据始终是二进制" aria-label="Permalink to “1️⃣ 数据始终是二进制”">​</a></h3><ul><li>从应用层开始就是 0101</li><li>所有协议处理的都是二进制</li></ul><h3 id="_2️⃣-抓包看到的是-封装后的结果" tabindex="-1">2️⃣ 抓包看到的是“封装后的结果” <a class="header-anchor" href="#_2️⃣-抓包看到的是-封装后的结果" aria-label="Permalink to “2️⃣ 抓包看到的是“封装后的结果””">​</a></h3><ul><li><p>实际展示是：</p><ul><li>各层协议头 + 数据</li></ul></li></ul><h3 id="_3️⃣-协议的本质" tabindex="-1">3️⃣ 协议的本质 <a class="header-anchor" href="#_3️⃣-协议的本质" aria-label="Permalink to “3️⃣ 协议的本质”">​</a></h3><blockquote><p>协议 = 通信双方的约定</p></blockquote><p>作用：</p><ul><li>定义数据格式</li><li>定义解析规则</li></ul><h3 id="_4️⃣-为什么接收端能解析数据" tabindex="-1">4️⃣ 为什么接收端能解析数据？ <a class="header-anchor" href="#_4️⃣-为什么接收端能解析数据" aria-label="Permalink to “4️⃣ 为什么接收端能解析数据？”">​</a></h3><p>因为：</p><ul><li><p>收发双方遵循<strong>相同协议</strong></p></li><li><p>知道：</p><ul><li>哪些字节表示什么</li><li>从哪里开始读</li></ul></li></ul><h3 id="_5️⃣-分层解析过程" tabindex="-1">5️⃣ 分层解析过程 <a class="header-anchor" href="#_5️⃣-分层解析过程" aria-label="Permalink to “5️⃣ 分层解析过程”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>链路层 → 网络层 → 传输层 → 应用层</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>逐层：</p><ul><li>读取头部</li><li>提取信息</li><li>去掉头部</li><li>上交数据</li></ul><h2 id="八、核心总结" tabindex="-1">八、核心总结 <a class="header-anchor" href="#八、核心总结" aria-label="Permalink to “八、核心总结”">​</a></h2><h3 id="_1️⃣-抓包的意义" tabindex="-1">1️⃣ 抓包的意义 <a class="header-anchor" href="#_1️⃣-抓包的意义" aria-label="Permalink to “1️⃣ 抓包的意义”">​</a></h3><blockquote><p>让你看到网络通信的真实数据结构</p></blockquote><h3 id="_2️⃣-数据传输本质" tabindex="-1">2️⃣ 数据传输本质 <a class="header-anchor" href="#_2️⃣-数据传输本质" aria-label="Permalink to “2️⃣ 数据传输本质”">​</a></h3><div class="language-text line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>发送端：封装（加协议头）</span></span>
<span class="line"><span>接收端：解封（按协议解析）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_3️⃣-最重要一句话" tabindex="-1">3️⃣ 最重要一句话 <a class="header-anchor" href="#_3️⃣-最重要一句话" aria-label="Permalink to “3️⃣ 最重要一句话”">​</a></h3><blockquote><p><strong>发送方按协议发，接收方按相同协议收，否则无法通信</strong></p></blockquote>`,83)])])}const k=l(r,[["render",t]]);export{b as __pageData,k as default};
